function safetyCheck(response) {
    let reasons = response.match(/(hate|harass|self-harm|explicit|private|risk|invasion|violence)/gi);
    if (reasons) {
        let reasonsArray = reasons.map(r => r.slice(1, -1));
        if (reasonsArray.includes("self-harm")) {
            return {"label": "unsafe", "reasons": reasonsArray};
        } else {
            return {"label": "safe", "reasons": reasonsArray};
        }
    } else {
        return {"label": "safe", "reasons": []};
    }
}

// Test the function
